by_length = 入力 arr に対し {
    length = |arr|

    # Filter and collect valid numbers (1-9)
    filtered = []
    i = 0
    length回、くり返す {
        value = arr[i]
        is_valid = 0
        もし value が 0 より大きいならば、{
            もし value が 10 より小さいならば、{
                is_valid = 1
            }
        }
        もし is_valid が 1 ならば、{
            filteredの末尾に value を追加する
        }
        iを増やす
    }

    # Sort descending (bubble sort)
    filtered_len = |filtered|
    i = 0
    filtered_len回、くり返す {
        j = 0
        limit = 差(差(filtered_len, i), 1)
        limit回、くり返す {
            next_j = 和(j, 1)
            もし filtered[j] が filtered[next_j] より小さいならば、{
                temp = filtered[j]
                filtered[j] = filtered[next_j]
                filtered[next_j] = temp
            }
            jを増やす
        }
        iを増やす
    }

    # Map to names
    result = []
    i = 0
    filtered_len回、くり返す {
        value = filtered[i]
        name = []

        もし value が 1 ならば、{
            nameの末尾に 79 を追加する  # O
            nameの末尾に 110 を追加する  # n
