            nameの末尾に 105 を追加する  # i
            nameの末尾に 118 を追加する  # v
            nameの末尾に 101 を追加する  # e
        }
        もし value が 6 ならば、{
            nameの末尾に 83 を追加する  # S
            nameの末尾に 105 を追加する  # i
            nameの末尾に 120 を追加する  # x
        }
        もし value が 7 ならば、{
            nameの末尾に 83 を追加する  # S
            nameの末尾に 101 を追加する  # e
            nameの末尾に 118 を追加する  # v
            nameの末尾に 101 を追加する  # e
            nameの末尾に 110 を追加する  # n
        }
        もし value が 8 ならば、{
            nameの末尾に 69 を追加する  # E
            nameの末尾に 105 を追加する  # i
            nameの末尾に 103 を追加する  # g
            nameの末尾に 104 を追加する  # h
            nameの末尾に 116 を追加する  # t
        }
        もし value が 9 ならば、{
